async function actionStep(input) {
  "use step";

  const clearintent = input.clearintent ?? {};

  const verificationStatusOk = clearintent.verification?.status === "verified";
  const intentHashOk =
    clearintent.verification?.intentHash != null &&
    clearintent.verification.intentHash === clearintent.intentHash;
  const policyHashOk =
    clearintent.verification?.policyHash != null &&
    clearintent.verification.policyHash === clearintent.policyHash;

  let status = "completed";
  let eventType = "clearintent.execution.completed";
  let error = null;
  let severity = "info";
  let shouldExecute = true;

  if (!verificationStatusOk) {
    status = "failed";
    eventType = "clearintent.execution.failed";
    error = "clearintent_verification_missing";
    severity = "critical";
    shouldExecute = false;
  } else if (!intentHashOk) {
    status = "failed";
    eventType = "clearintent.execution.failed";
    error = "intent_hash_mismatch";
    severity = "critical";
    shouldExecute = false;
  } else if (!policyHashOk) {
    status = "failed";
    eventType = "clearintent.execution.failed";
    error = "policy_hash_mismatch";
    severity = "critical";
    shouldExecute = false;
  }

  return {
    success: true,
    status,
    eventType,
    error,
    severity,
    shouldExecute,

    parentWallet: clearintent.parentWallet ?? null,
    agentAccount: clearintent.agentAccount ?? null,
    agentEnsName: clearintent.agentEnsName ?? null,

    intentHash: clearintent.intentHash ?? null,
    verificationIntentHash: clearintent.verification?.intentHash ?? null,
    policyHash: clearintent.policyHash ?? null,
    verificationPolicyHash: clearintent.verification?.policyHash ?? null,
    auditLatest: clearintent.auditLatest ?? null,

    actionType: clearintent.action?.actionType ?? null,
    target: clearintent.action?.target ?? null,
    chainId: clearintent.action?.chainId ?? null,
    valueLimit: clearintent.action?.valueLimit ?? null,

    executor: clearintent.authority?.executor ?? null,
    signer: clearintent.authority?.signer ?? null,
    transactionHash: null
  };
}
